import 'dart:convert';import 'package:dio/dio.dart';import 'package:flutter_test/flutter_test.dart';import 'package:meme_arena/features/api_repository.dart';
class MockAdapter extends HttpClientAdapter{MockAdapter(this.handler);final ResponseBody Function(RequestOptions) handler;@override Future<ResponseBody> fetch(RequestOptions options,Stream<List<int>>? requestStream,Future<void>? cancelFuture)async=>handler(options);@override void close({bool force=false}){}}
ResponseBody jsonBody(Object o,{int status=200})=>ResponseBody.fromString(jsonEncode(o),status,headers:{Headers.contentTypeHeader:[Headers.jsonContentType]});
void main(){late Dio dio;late ApiRepository repo;setUp((){dio=Dio(BaseOptions(baseUrl:'http://x'));repo=ApiRepository(dio,()async=>'u1');});test('create guest user',()async{dio.httpClientAdapter=MockAdapter((o){expect(o.path,'/api/v1/users/guest');return jsonBody({'id':'u1','nickname':'bob','votesCount':0,'submittedMemesCount':0},status:201);});expect((await repo.createGuest('bob')).nickname,'bob');});test('get profile',()async{dio.httpClientAdapter=MockAdapter((o)=>jsonBody({'id':'u1','nickname':'bob','votesCount':2,'submittedMemesCount':1}));expect((await repo.getProfile('u1')).votesCount,2);});test('get next battle',()async{dio.httpClientAdapter=MockAdapter((o)=>jsonBody({'battleId':'b','left':{'id':'l','title':'L','contentUrl':'/l','rating':1},'right':{'id':'r','title':'R','contentUrl':'/r','rating':2}}));expect((await repo.getNextBattle())!.left.title,'L');});test('204 no battle',()async{dio.httpClientAdapter=MockAdapter((o)=>ResponseBody.fromString('',204));expect(await repo.getNextBattle(),isNull);});test('submit vote',()async{dio.httpClientAdapter=MockAdapter((o){expect(o.path,'/api/v1/votes');return jsonBody({},status:201);});final b=await ApiRepository(Dio()..httpClientAdapter=MockAdapter((o)=>jsonBody({'battleId':'b','left':{'id':'l','title':'L','imageUrl':'/l','rating':1},'right':{'id':'r','title':'R','imageUrl':'/r','rating':2}})),()async=>'u1').getNextBattle();await repo.submitVote(b!,'l');});test('get top',()async{dio.httpClientAdapter=MockAdapter((o)=>jsonBody({'items':[{'position':1,'memeId':'m','title':'T','contentUrl':'/m','rating':9,'wins':1,'losses':0,'battlesCount':1}]}));expect((await repo.getTop()).single.battlesCount,1);});test('create meme with imageUrl',()async{dio.httpClientAdapter=MockAdapter((o){expect((o.data as Map)['imageUrl'],'http://i');return jsonBody({},status:201);});await repo.createMeme(title:'t',imageUrl:'http://i');});test('upload image if endpoint implemented method exists',(){expect(repo.uploadImage,isA<Function>());});}
